import json
import base64


def confirmAuth(headers):
    try:
        auth_token = headers['AuthToken']
    except KeyError:
        return None
    try:
        decoded = base64.b64decode(auth_token, validate=True)
    except (base64.binascii.Error, ValueError):
        return None
    try:
        token = json.loads(decoded)
    except (json.JSONDecodeError, ValueError, TypeError):
        return None
    if isinstance(token, dict) and token.get('is_valid') is True:
        return token.get('data', None)
    return None
